# Category: oidc_security

from flask import Flask, redirect, request, session, url_for, render_template_string
import secrets
import urllib.parse

app = Flask(__name__)
app.secret_key = "change-me"

CLIENT_ID = "your-client-id"
AUTHORIZATION_ENDPOINT = "https://your-idp.example.com/authorize"
REDIRECT_URI = "http://localhost:5000/callback"

HOME_TEMPLATE = """
<!doctype html>
<html>
  <body>
    <h1>OIDC Client</h1>
    {% if user %}
      <p>Authenticated</p>
      <pre>{{ user }}</pre>
      <a href="{{ url_for('logout') }}">Logout</a>
    {% else %}
      <a href="{{ url_for('login') }}">Login</a>
    {% endif %}
  </body>
</html>
"""

CALLBACK_TEMPLATE = """
<!doctype html>
<html>
  <body>
    <script>
      const hash = window.location.hash.substring(1);
      const params = new URLSearchParams(hash);
      const idToken = params.get('id_token');
      const state = params.get('state');

      if (!idToken || !state) {
        document.body.innerText = 'Missing id_token or state';
      } else {
        const form = document.createElement('form');
        form.method = 'POST';
        form.action = '{{ url_for("callback") }}';

        const idTokenInput = document.createElement('input');
        idTokenInput.type = 'hidden';
        idTokenInput.name = 'id_token';
        idTokenInput.value = idToken;
        form.appendChild(idTokenInput);

        const stateInput = document.createElement('input');
        stateInput.type = 'hidden';
        stateInput.name = 'state';
        stateInput.value = state;
        form.appendChild(stateInput);

        document.body.appendChild(form);
        form.submit();
      }
    </script>
  </body>
</html>
"""

@app.route("/")
def index():
    return render_template_string(HOME_TEMPLATE, user=session.get("id_token"))

@app.route("/login")
def login():
    state = secrets.token_urlsafe(32)
    session["oidc_state"] = state

    query = {
        "client_id": CLIENT_ID,
        "redirect_uri": REDIRECT_URI,
        "scope": "openid",
        "response_type": "id_token",
        "state": state,
    }
    url = AUTHORIZATION_ENDPOINT + "?" + urllib.parse.urlencode(query)
    return redirect(url)

@app.route("/callback", methods=["GET", "POST"])
def callback():
    if request.method == "GET":
        return render_template_string(CALLBACK_TEMPLATE)

    returned_state = request.form.get("state")
    id_token = request.form.get("id_token")
    expected_state = session.get("oidc_state")

    if not expected_state or returned_state != expected_state:
        return "Invalid state", 400

    if not id_token:
        return "Missing id_token", 400

    session["id_token"] = id_token
    session.pop("oidc_state", None)
    return redirect(url_for("index"))

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))

if __name__ == "__main__":
    app.run(debug=True)